output_base = "/mnt/shared-storage-user/sfteval/yujiashuo/datapick/tiny2m_output/20251230_newstart/"
output_json = "/mnt/shared-storage-user/yujiashuo/verification/export_meta/export_meta_s1_1_mm_sft_full_1230_tiny2M.json"
num_workers = 32
def count_lines_streaming(file_path):
    """Count lines in a file using streaming (memory efficient)"""
    try:
        count = 0
        with open(file_path, 'r', encoding='utf-8', errors='ignore') as f:
            for _ in f:
                count += 1
        return count
    except Exception:
        return 0
def count_lines_wc(path):
    """Count lines using wc -l command
    If path is a directory, count all jsonl files and sum their line counts
    If path is a file, count lines in that file
    """
    try:
        if os.path.isdir(path):
            # Count all jsonl files in directory and sum their lengths
            total_lines = 0
            # First try to find jsonl files
            jsonl_files = [f for f in os.listdir(path) 
                          if os.path.isfile(os.path.join(path, f)) and f.endswith('.jsonl')]

            if jsonl_files:
                # Count jsonl files
                for filename in sorted(jsonl_files):
                    file_path = os.path.join(path, filename)
                    try:
                        result = subprocess.run(['wc', '-l', file_path], capture_output=True, text=True, timeout=30)
                        if result.returncode == 0:
                            lines = int(result.stdout.split()[0])
                            total_lines += lines
                    except (subprocess.TimeoutExpired, ValueError, IndexError, Exception):
                        pass
            else:
                # If no jsonl files, count all files in directory
                all_files = [f for f in os.listdir(path) if os.path.isfile(os.path.join(path, f))]
                for filename in sorted(all_files):
                    file_path = os.path.join(path, filename)
                    try:
                        result = subprocess.run(['wc', '-l', file_path], capture_output=True, text=True, timeout=30)
                        if result.returncode == 0:
                            lines = int(result.stdout.split()[0])
                            total_lines += lines
                    except (subprocess.TimeoutExpired, ValueError, IndexError, Exception):
                        pass

            return total_lines
        elif os.path.isfile(path):
            # Count lines in single file
            try:
                result = subprocess.run(['wc', '-l', path], capture_output=True, text=True, timeout=30)
                if result.returncode == 0:
                    return int(result.stdout.split()[0])
            except (subprocess.TimeoutExpired, ValueError, IndexError, Exception):
                pass
        return 0
    except Exception:
        return 0
def sample_file(input_file, output_file, sample_ratio):
    """Sample lines from input file to output file (memory efficient for large files)"""
    try:
        # First pass: count total lines
        total_lines = 0
        with open(input_file, 'r', encoding='utf-8', errors='ignore') as f:
            for _ in f:
                total_lines += 1

        if total_lines == 0:
            return True, 0, 0

        sample_size = max(1, int(total_lines * sample_ratio))

        if sample_size >= total_lines:
            # Copy all lines
            os.makedirs(os.path.dirname(output_file), exist_ok=True)
            with open(input_file, 'r', encoding='utf-8', errors='ignore') as fin:
                with open(output_file, 'w', encoding='utf-8') as fout:
                    for line in fin:
                        fout.write(line)
            return True, total_lines, total_lines
        else:
            # Sample lines: generate random line indices
            selected_indices = set(random.sample(range(total_lines), sample_size))

            # Second pass: write selected lines
            os.makedirs(os.path.dirname(output_file), exist_ok=True)
            line_idx = 0
            with open(input_file, 'r', encoding='utf-8', errors='ignore') as fin:
                with open(output_file, 'w', encoding='utf-8') as fout:
                    for line in fin:
                        if line_idx in selected_indices:
                            fout.write(line)
                        line_idx += 1

            return True, total_lines, sample_size
    except Exception as e:
        return False, str(e), 0
def check_output_exists(original_path, output_base, quick_check=False):
    """Check if output already exists and is valid

    Args:
        original_path: Original data path
        output_base: Output base directory
        quick_check: If True, only check existence, don't count lines (saves memory)
    """
    original_path = original_path.rstrip('/')

    if original_path.startswith('/mnt/shared-storage-user/puyullmgpu-shared/puyu3-delivery/'):
        relative_path = original_path.replace('/mnt/shared-storage-user/puyullmgpu-shared/puyu3-delivery/', '')
    elif original_path.startswith('/mnt/shared-storage-user/sfteval/sft_data_delivery/'):
        relative_path = original_path.replace('/mnt/shared-storage-user/sfteval/sft_data_delivery/', '')
    elif original_path.startswith('/mnt/shared-storage-user/intern-multi-modal-delivery/'):
        relative_path = original_path.replace('/mnt/shared-storage-user/intern-multi-modal-delivery/', '')
    elif original_path.startswith('/mnt/shared-storage-user/sfteval/sft_data_delivery/'):
        relative_path = original_path.replace('/mnt/shared-storage-user/sfteval/sft_data_delivery/', '')
    elif original_path.startswith('/mnt/shared-storage-user/'):
        relative_path = original_path.replace('/mnt/shared-storage-user/', '')
    else:
        parts = original_path.split('/')
        if len(parts) > 1:
            relative_path = '/'.join(parts[-2:])
        else:
            relative_path = os.path.basename(original_path)

    output_path = os.path.join(output_base, relative_path)
    if os.path.isdir(original_path):
        output_path = output_path.rstrip('/')
        if os.path.exists(output_path) and os.path.isdir(output_path):
            files = [f for f in os.listdir(output_path) if os.path.isfile(os.path.join(output_path, f))]
            if files:
                if quick_check:
                    # Quick check: just verify files exist
                    return True, output_path, len(files), 0, 0

                # Full check: count lines using streaming
                total_original = 0
                total_sampled = 0
                for filename in files:
                    output_file = os.path.join(output_path, filename)
                    if os.path.exists(output_file):
                        total_sampled += count_lines_streaming(output_file)
                    # Count original lines
                    input_file = os.path.join(original_path, filename)
                    if os.path.exists(input_file):
                        total_original += count_lines_streaming(input_file)
                return True, output_path, len(files), total_original, total_sampled
    elif os.path.isfile(original_path):
        output_file = os.path.join(os.path.dirname(output_path), os.path.basename(original_path))
        if os.path.exists(output_file) and os.path.isfile(output_file):
            if quick_check:
                return True, os.path.dirname(output_path), 1, 0, 0
            total_sampled = count_lines_streaming(output_file)
            total_original = count_lines_streaming(original_path)
            return True, os.path.dirname(output_path), 1, total_original, total_sampled

    return False, None, 0, 0, 0
def process_dataset(args):
    key, value, output_base = args

    try:
        original_path = value['annotation'].rstrip('/')
        sample_ratio = value['sample_ratio']

        if not os.path.exists(original_path):
            return key, False, f"Original path does not exist: {original_path}"

        # Check if output already exists (resume mechanism)
        # Use quick_check=False to get accurate line counts for processing
        exists, output_path, files_count, total_original, total_sampled = check_output_exists(original_path, output_base, quick_check=False)
        if exists:
            return key, True, {
                'output_path': output_path,
                'total_original': total_original,
                'total_sampled': total_sampled,
