        elif original_path.startswith('/mnt/shared-storage-user/intern-multi-modal-delivery/'):
            relative_path = original_path.replace('/mnt/shared-storage-user/intern-multi-modal-delivery/', '')
        elif original_path.startswith('/mnt/shared-storage-user/sfteval/sft_data_delivery/'):
            relative_path = original_path.replace('/mnt/shared-storage-user/sfteval/sft_data_delivery/', '')
        elif original_path.startswith('/mnt/shared-storage-user/'):
            relative_path = original_path.replace('/mnt/shared-storage-user/', '')
        else:
