            if len(parts) > 1:
                relative_path = '/'.join(parts[-2:])
            else:
                relative_path = os.path.basename(original_path)

        output_path = os.path.join(output_base, relative_path)
        if os.path.isdir(original_path):
            output_path = output_path.rstrip('/')
        else:
            output_path = os.path.dirname(output_path)

        total_original = 0
        total_sampled = 0
        files_processed = 0

        if os.path.isdir(original_path):
            files = sorted([f for f in os.listdir(original_path) 
                          if os.path.isfile(os.path.join(original_path, f))])

            if not files:
                return key, False, f"No files found in: {original_path}"

            for filename in files:
                input_file = os.path.join(original_path, filename)
                output_file = os.path.join(output_path, filename)

                success, info1, info2 = sample_file(input_file, output_file, sample_ratio)

                if success:
                    total_original += info1
                    total_sampled += info2
                    files_processed += 1
                else:
                    print(f"Error processing {input_file}: {info1}")

        elif os.path.isfile(original_path):
            filename = os.path.basename(original_path)
            output_file = os.path.join(output_path, filename)
            success, info1, info2 = sample_file(original_path, output_file, sample_ratio)

            if success:
                total_original = info1
                total_sampled = info2
                files_processed = 1
            else:
                return key, False, f"Error processing file: {info1}"
        else:
            return key, False, f"Path is neither file nor directory: {original_path}"

        return key, True, {
            'output_path': output_path,
            'total_original': total_original,
            'total_sampled': total_sampled,
            'files_processed': files_processed,
            'skipped': False
        }
    except Exception as e:
        return key, False, f"Exception: {str(e)}\n{traceback.format_exc()}"
def check_and_fix_datasets(data, output_base, existing_output):
    """Check each dataset one by one and fix incomplete ones (single process)
    Uses quick_check to avoid OOM when checking many datasets
    """
    print("\nChecking all datasets one by one...")
    print("Using memory-efficient quick check mode...")

    results = []
    fixed = 0
    already_complete = 0

    # First pass: quick check to identify what needs processing
    need_processing = []
    for key, value in tqdm(data.items(), desc="Quick checking datasets"):
        original_path = value['annotation'].rstrip('/')

        # Quick check: only verify existence, don't count lines
        exists, _, _, _, _ = check_output_exists(original_path, output_base, quick_check=True)

        if exists and key in existing_output:
            # Already complete
            already_complete += 1
        else:
            # Need to process
            need_processing.append((key, value))

    print(f"\nFound {already_complete} already complete, {len(need_processing)} need processing")

    # Second pass: process only what's needed
    if need_processing:
        print("\nProcessing incomplete datasets...")
        for key, value in tqdm(need_processing, desc="Processing datasets"):
            result = process_dataset((key, value, output_base))
            results.append(result)

            if result[1]:  # success
                fixed += 1
                status = "⏭ Skipped" if result[2].get('skipped', False) else "✓ Fixed"
                if fixed % 10 == 0 or not result[2].get('skipped', False):
                    print(f"  {status} {key}: {result[2].get('files_processed', 0)} files, {result[2].get('total_original', 0)} -> {result[2].get('total_sampled', 0)} lines")
            else:
                print(f"  ✗ Failed {key}: {str(result[2])[:100]}")

    print(f"\nCheck complete: {len(data)} checked, {already_complete} already complete, {fixed} fixed/processed")
    return results
def main(check_mode=False, build_mode=False):
    print(f"Loading JSON from: {input_json}")
    with open(input_json, 'r', encoding='utf-8') as f:
        data = json.load(f)

    print(f"Total datasets: {len(data)}")
    print(f"Output base: {output_base}")

    os.makedirs(output_base, exist_ok=True)

    # Check for existing output JSON (resume mechanism)
    existing_output = {}
    if os.path.exists(output_json):
        print(f"\nFound existing output JSON: {output_json}")
        print("Resuming from previous run...")
        with open(output_json, 'r', encoding='utf-8') as f:
            existing_output = json.load(f)
        print(f"  Found {len(existing_output)} existing entries")

    # Build mode: only generate JSON, no sampling, no validation
    if build_mode:
        print("\n" + "=" * 80)
        print("BUILD MODE: Generating output JSON (no sampling, no validation)")
        print("=" * 80)

        output_data = {}

        for key, value in tqdm(data.items(), desc="Building output JSON"):
            original_path = value['annotation'].rstrip('/')

            # Add _tiny suffix to dataset name
            new_key = key + '_tiny'

            # Calculate output path based on original path
            if original_path.startswith('/mnt/shared-storage-user/puyullmgpu-shared/puyu3-delivery/'):
                relative_path = original_path.replace('/mnt/shared-storage-user/puyullmgpu-shared/puyu3-delivery/', '')
            elif original_path.startswith('/mnt/shared-storage-user/sfteval/sft_data_delivery/'):
                relative_path = original_path.replace('/mnt/shared-storage-user/sfteval/sft_data_delivery/', '')
            elif original_path.startswith('/mnt/shared-storage-user/intern-multi-modal-delivery/'):
                relative_path = original_path.replace('/mnt/shared-storage-user/intern-multi-modal-delivery/', '')
            elif original_path.startswith('/mnt/shared-storage-user/sfteval/sft_data_delivery/'):
                relative_path = original_path.replace('/mnt/shared-storage-user/sfteval/sft_data_delivery/', '')
            elif original_path.startswith('/mnt/shared-storage-user/'):
                relative_path = original_path.replace('/mnt/shared-storage-user/', '')
            else:
                parts = original_path.split('/')
                if len(parts) > 1:
                    relative_path = '/'.join(parts[-2:])
                else:
                    relative_path = os.path.basename(original_path)

            output_path = os.path.join(output_base, relative_path)
            if os.path.isdir(original_path):
                output_path = output_path.rstrip('/')
            else:
                output_path = os.path.dirname(output_path)

            if not output_path.endswith('/'):
                output_path += '/'

            # Count lines using wc -l from output path (sampled data)
            actual_length = count_lines_wc(output_path)
            if actual_length == 0:
                # Fallback: try original path if output doesn't exist yet
                actual_length = count_lines_wc(original_path)

            # Set sample_ratio to 1.0 for already sampled data
            output_data[new_key] = {
                'data_augment': value.get('data_augment', True),
                'sample_ratio': 1.0,  # Set to 1.0 for already sampled data
                'annotation': output_path,
                'media_root': value.get('media_root'),
                'length': actual_length  # Use wc -l count
            }

        # Calculate total length
        total_length = sum(v.get('length', 0) for v in output_data.values())

        print(f"\nSummary:")
        print(f"  Total entries in JSON: {len(output_data)}")
        print(f"  Total length (sum of all lengths): {total_length:,}")

        print(f"\nSaving output JSON to: {output_json}")
        with open(output_json, 'w', encoding='utf-8') as f:
            json.dump(output_data, f, ensure_ascii=False, indent=4)

        print(f"✓ Output JSON saved with {len(output_data)} entries")
        print(f"✓ Total data length: {total_length:,}")
        print("Done!")
        return

    # Normal modes: sampling
    skipped_count = 0  # Initialize for both modes
    results = []  # Initialize results list

    if check_mode:
        # Check mode: single process, check and fix all datasets
        print("\n" + "=" * 80)
        print("CHECK MODE: Single process checking and fixing all datasets")
        print("=" * 80)
        results = check_and_fix_datasets(data, output_base, existing_output)
        # Count skipped from existing_output
        skipped_count = len(existing_output)
    else:
