            shown += 1
    if shown == 10:
        print(f"  ... (showing first 10 entries, {len(results) - shown} more)")

    print(f"\nSummary:")
    print(f"  Total processed: {len(existing_output) + len(results)}")
    print(f"  Newly processed: {successful - len(existing_output)}")
    print(f"  Skipped (already done): {skipped_this_run + skipped_count}")
    print(f"  Failed: {failed}")

    print("Done!")
if __name__ == '__main__':
    parser = argparse.ArgumentParser(description='Sample datasets from JSON (multimodal)')
    parser.add_argument('--check', action='store_true', 
                       help='Check mode: use single process to check and fix all datasets one by one')
    parser.add_argument('--build', action='store_true',
                       help='Build mode: generate output JSON file directly from input JSON (no sampling, no validation)')
    args = parser.parse_args()

    random.seed(42)
    main(check_mode=args.check, build_mode=args.build)
